def solve(*args):
    if not args:
        return "No submissions provided"

    submissions = args[0]

    if not isinstance(submissions, list):
        return "Submissions must be a list"

    if any(not isinstance(submission, dict) for submission in submissions):
        return "Each submission must be a dictionary"

    valid_submissions = []

    for submission in submissions:
        if 'id' in submission and 'status' in submission:
            valid_submissions.append(submission)
        else:
            return "Invalid submission format"

    return valid_submissions
